def ddev_rule(model, gg, yy):
    return sum(model.dev[c, yy] * model.xca[gg, c] for c in model.c) == model.pdev[gg, yy] - model.ndev[gg, yy]
model.ddev = Constraint(model.g, model.y, rule=ddev_rule)

def cmbq_rule(model, gg, q):
    return sum(model.yq[ll, q] * model.animal[gg, ll] for ll in model.l) - model.slc[gg, q] - model.clc[gg, q] + model.plc[gg, q] == 0.0
model.cmbq = Constraint(model.g, model.q, rule=cmbq_rule)

def cblc_rule(model, gg, c):
    cc = set(model.cc)
    if c not in cc:
        return Constraint.Skip
    return model.ccc[gg, c] >= model.alphc[gg, c] + model.betac[gg, c] * model.yva[gg]
model.cblc = Constraint(model.g, model.c, rule=cblc_rule)

def cblq_rule(model, gg, q):
    return model.clc[gg, q] >= model.alphq[gg, q] + model.betaq[gg, q] * model.yva[gg]
model.cblq = Constraint(model.g, model.q, rule=cblq_rule)

def buca_rule(model, gg):
    return model.animal[gg, 'bullock'] <= model.repco * model.animal[gg, 'cattle']
model.buca = Constraint(model.g, rule=buca_rule)

def trcp_rule(model, gg, mm):
    return model.ts[gg, mm] <= model.areac_trg1[gg] / 1000.0 + model.trcap * model.itr[gg]
model.trcp = Constraint(model.g, model.m, rule=trcp_rule)

def cacr_rule(model, gg, c):
    tech_by_c = [(t, s, w) for (cx, t, s, w) in model.tech if cx in (c,)]
    return model.xca[gg, c] == sum(model.x[gg, c, t, s, w] for (t, s, w) in tech_by_c)
model.cacr = Constraint(model.g, model.c, rule=cacr_rule)

def tbcp_rule(model, gg, mm):
    fsg = set(model.fsg)
    if gg not in fsg:
        return Constraint.Skip
    return model.tw[gg, mm] <= model.areac_twg[gg] / 1000.0 + model.twcap * model.itw[gg]
model.tbcp = Constraint(model.g, model.m, rule=tbcp_rule)
